namespace CourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

public class Instructor
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Bio { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;
}

public class Course
{
    public int Id { get; set; }
    public string Code { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public Department Department { get; set; } = null!;
    public Instructor Instructor { get; set; } = null!;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace CourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{2}\d{6}$", ErrorMessage = "Student ID must be 2 uppercase letters followed by 6 digits (e.g., CS123456).")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using CourseCatalog.Models;

namespace CourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Code = "ENG", Name = "English", Description = "Study of literature, writing, and communication." },
            new() { Id = 4, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and fundamental forces." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Study of past events and human civilization." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Sarah Chen", Title = "Professor", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers and received the ACM Distinguished Scientist award.", Email = "s.chen@university.edu" },
            new() { Id = 2, Name = "Dr. James Miller", Title = "Associate Professor", Bio = "Dr. Miller's research focuses on abstract algebra and number theory. He has been teaching at the university for 12 years.", Email = "j.miller@university.edu" },
            new() { Id = 3, Name = "Prof. Emily Watson", Title = "Professor", Bio = "Prof. Watson is a published novelist and literary critic specializing in 20th-century American literature.", Email = "e.watson@university.edu" },
            new() { Id = 4, Name = "Dr. Robert Park", Title = "Professor", Bio = "Dr. Park's research interests include quantum mechanics and condensed matter physics. He leads the university's quantum computing lab.", Email = "r.park@university.edu" },
            new() { Id = 5, Name = "Dr. Maria Garcia", Title = "Associate Professor", Bio = "Dr. Garcia is a historian specializing in Latin American history and postcolonial studies.", Email = "m.garcia@university.edu" },
            new() { Id = 6, Name = "Dr. Alan Turing II", Title = "Assistant Professor", Bio = "Dr. Turing focuses on algorithms, data structures, and computational complexity theory.", Email = "a.turing@university.edu" },
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Code = "CS101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using Python. Covers variables, control flow, functions, and basic data structures.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, Instructor = _instructors[0], Department = _departments[0], IsFeatured = true },
            new() { Id = 2, Code = "CS201", Title = "Data Structures & Algorithms", Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming).", Credits = 4, Schedule = "Tue/Thu 10:00–11:50 AM", DepartmentId = 1, Instructor = _instructors[5], Department = _departments[0], IsFeatured = true },
            new() { Id = 3, Code = "CS301", Title = "Artificial Intelligence", Description = "Introduction to AI concepts including search, knowledge representation, machine learning, and neural networks.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, Instructor = _instructors[0], Department = _departments[0], IsFeatured = false },
            new() { Id = 4, Code = "MATH101", Title = "Calculus I", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, Instructor = _instructors[1], Department = _departments[1], IsFeatured = false },
            new() { Id = 5, Code = "MATH201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues and eigenvectors.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, Instructor = _instructors[1], Department = _departments[1], IsFeatured = true },
            new() { Id = 6, Code = "ENG101", Title = "College Writing", Description = "Develop critical reading, thinking, and writing skills. Focus on argumentation and research-based essays.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, Instructor = _instructors[2], Department = _departments[2], IsFeatured = false },
            new() { Id = 7, Code = "ENG205", Title = "American Literature", Description = "Survey of American literature from the colonial period to the present, with emphasis on major authors and literary movements.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentId = 3, Instructor = _instructors[2], Department = _departments[2], IsFeatured = false },
            new() { Id = 8, Code = "PHYS101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to classical physics.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM + Lab Thu 2:00–4:50 PM", DepartmentId = 4, Instructor = _instructors[3], Department = _departments[3], IsFeatured = true },
            new() { Id = 9, Code = "PHYS301", Title = "Quantum Mechanics", Description = "Wave functions, Schrödinger equation, quantum states, and measurement theory.", Credits = 3, Schedule = "Tue/Thu 10:00–11:20 AM", DepartmentId = 4, Instructor = _instructors[3], Department = _departments[3], IsFeatured = false },
            new() { Id = 10, Code = "HIST101", Title = "World History to 1500", Description = "Survey of world civilizations from prehistory through the Renaissance, covering major cultural, political, and economic developments.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", DepartmentId = 5, Instructor = _instructors[4], Department = _departments[4], IsFeatured = false },
        };
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? search = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(search))
        {
            var term = search.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();
}

